import org.slf4j.LoggerFactory;
import java.util.HashMap;
import java.util.Map;

/**
 * Service for processing user profiles.
 */
public class UserProfileService {

    private static final Logger logger = LoggerFactory.getLogger(UserProfileService.class);

    // Simulating a user data repository
    private static final Map<String, UserProfile> userDatabase = new HashMap<>();

    static {
        // Initialize with pre-existing user data
        userDatabase.put("1", new UserProfile("1", "John Doe", "330101199001011234", "13800138000"));
        userDatabase.put("2", new UserProfile("2", "Jane Smith", "330101199202025678", "13912345678"));
    }

    /**
     * Processes a user profile based on the provided userId.
     * 
     * @param userId the unique identifier of the user to process
     * @throws IllegalArgumentException if userId is null or empty
     * @throws UserNotFoundException if user with given userId doesn't exist
     */
    public void processUserProfile(String userId) {
        // Input validation
        if (userId == null || userId.trim().isEmpty()) {
            logger.error("Invalid userId provided: {}", userId);
            throw new IllegalArgumentException("User ID cannot be null or empty");
        }

        // Log the user currently being processed for debugging
        logger.info("Processing user profile for userId: {}", userId);

        try {
            // Simulate fetching user information
            UserProfile user = fetchUserProfile(userId);

            // Log additional information about the user being processed
            logger.info("Processing user: {} (ID Card: {}, Phone: {})", 
                user.getUsername(), user.getIdCard(), user.getPhoneNumber());

            // Here you would add actual business logic for processing the user profile
            // For example: validation, data transformation, integration with other services, etc.

        } catch (UserNotFoundException e) {
            logger.error("User not found with userId: {}", userId);
            throw e;
        } catch (Exception e) {
            logger.error("Unexpected error processing user profile for userId: {}", userId, e);
            throw new RuntimeException("Failed to process user profile", e);
        }
    }

    /**
     * Fetches user profile from the simulated database.
     * 
     * @param userId the user identifier
     * @return the UserProfile object
     * @throws UserNotFoundException if user doesn't exist
     */
    private UserProfile fetchUserProfile(String userId) {
        UserProfile user = userDatabase.get(userId);
        if (user == null) {
            throw new UserNotFoundException("User with ID " + userId + " not found");
        }
        return user;
    }

    /**
     * Custom exception for user not found scenarios.
     */
    public static class UserNotFoundException extends RuntimeException {
        public UserNotFoundException(String message) {
            super(message);
        }
    }
}

